const s = $('Query Stats').first().json;
const recent = $('Last 10 Processed').all().map(i => i.json);
const failures = $('Failed Companies').all().map(i => i.json);

// Proxy stats (may be empty if table doesn't exist yet)
let proxyInfo = 'No proxy table yet';
try {
  const proxyItems = $('Proxy Stats').all();
  if (proxyItems.length > 0) {
    proxyInfo = proxyItems.map(p => `${p.json.status}: ${p.json.cnt} (avg ${p.json.avg_ms || '?'}ms)`).join(' | ');
  }
} catch(e) { proxyInfo = 'Table not created yet'; }

// Tier 1-3 pipeline
const v6Total = parseInt(s.v6_total) || 0;
const v6Enriched = parseInt(s.v6_enriched) || 0;
const v6Failed = parseInt(s.v6_failed) || 0;
const v6FailedRetry = parseInt(s.v6_failed_retry) || 0;
const v6Fixed = parseInt(s.v6_fixed_by_retry) || 0;
const TARGET_V6 = 6123;

// Tier 4-5 pipeline
const t45Total = parseInt(s.t45_total) || 0;
const t45Enriched = parseInt(s.t45_enriched) || 0;
const t45Failed = parseInt(s.t45_failed) || 0;
const t45FailedRetry = parseInt(s.t45_failed_retry) || 0;
const t45Fixed = parseInt(s.t45_fixed_by_retry) || 0;
const TARGET_T45 = 16816;

// Grand totals
const grandTotal = parseInt(s.grand_total) || 0;
const TARGET_ALL = TARGET_V6 + TARGET_T45;

// By tier
const t1 = parseInt(s.tier1) || 0;
const t2 = parseInt(s.tier2) || 0;
const t3 = parseInt(s.tier3) || 0;
const t4 = parseInt(s.tier4) || 0;
const t5 = parseInt(s.tier5) || 0;

const avgSec = s.avg_sec || 'N/A';
const t45Remaining = TARGET_T45 - t45Total;
const etaHours = t45Remaining > 0 ? ((t45Remaining * (parseFloat(avgSec || 5) + 15)) / 3600).toFixed(1) : '0';

return { json: {
  '📊 PIPELINE MONITOR v2': '════════════════════════════',
  grand_total: `${grandTotal} / ${TARGET_ALL} (${((grandTotal/TARGET_ALL)*100).toFixed(1)}%)`,
  '🔵 TIER 1-3 (v6)': '────────────────',
  v6_progress: `${v6Total} / ${TARGET_V6} (${((v6Total/TARGET_V6)*100).toFixed(1)}%)`,
  v6_enriched: v6Enriched,
  v6_failed: v6Failed,
  v6_failed_retry: v6FailedRetry,
  v6_fixed_by_retry: v6Fixed,
  v6_success_rate: `${v6Total > 0 ? (((v6Total - v6Failed - v6FailedRetry) / v6Total) * 100).toFixed(1) : 0}%`,
  '🟢 TIER 4-5 (t45)': '────────────────',
  t45_progress: `${t45Total} / ${TARGET_T45} (${((t45Total/TARGET_T45)*100).toFixed(1)}%)`,
  t45_enriched: t45Enriched,
  t45_failed: t45Failed,
  t45_failed_retry: t45FailedRetry,
  t45_fixed_by_retry: t45Fixed,
  t45_remaining: t45Remaining,
  t45_eta: `~${etaHours} hours`,
  '📈 BY TIER': '────────────────',
  tier1: `${t1} (≥1000 emp)`,
  tier2: `${t2} (500-999)`,
  tier3: `${t3} (100-499)`,
  tier4: `${t4} (50-99)`,
  tier5: `${t5} (20-49)`,
  '🔗 PROXIES': '────────────────',
  proxy_status: proxyInfo,
  '⏱️ TIMING': '────────────────',
  avg_duration: `${avgSec}s`,
  avg_fields: s.avg_fields || 'N/A',
  started_at: s.started_at || 'N/A',
  last_updated: s.last_updated || 'N/A',
  '📋 LAST 10': '────────────────',
  recent: recent.map(r => `${r.ruc} | ${(r.razon_social||'').substring(0,30)} | ${r.status} | ${r.fields} flds | ${r.tier} | ${r.source}`),
  '❌ FAILURES': '────────────────',
  total_failing: (v6Failed + v6FailedRetry + t45Failed + t45FailedRetry),
  failed_list: failures.map(f => `${f.ruc} | ${(f.razon_social||'').substring(0,25)} | ${f.status} | ${f.tier} | ${f.error || 'no detail'}`)
}};
